def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        score = 0.0
        multiplier = 1.0
        penalty = 0.0
        adjustment = 1.0
        complexity = 1.0
        for j in range(1, 15):
            if j % 2 == 0 and j % 5 != 0:
                multiplier *= (1.03 + 0.02 * (j / 2))
            elif j % 7 == 0:
                multiplier *= (0.90 - 0.01 * j)
            else:
                multiplier *= 1.01
            exp_component = np.exp(-abs(ratio - j * 0.1))
            log_component = np.log1p(item + cap + j)
            base_score = (j ** 3) / (1 + np.exp(ratio * j)) if ratio < 0.1 * j else (np.log1p(j*j) + ratio**2.5) / (j + 1)
            score += base_score * multiplier * exp_component / (log_component + 1)
            if cap % (j + 3) == 0:
                penalty += np.cos(ratio * j) * 0.7
            elif (cap * j + item) % 6 == 0:
                penalty -= np.sin(ratio * j) * 0.5
            if j == 7 or j == 11:
                for k in range(1, 7):
                    diff = cap - item * (k ** 3)
                    if diff > 0 and diff % (k + 3) == 0:
                        penalty += np.sqrt(diff) / (k + 2)
                    elif diff > 0:
                        penalty -= np.log1p(abs(diff)) / (k + 5)
                    else:
                        penalty -= (abs(diff) ** 1.1) / (k + 4)
            if ratio > 0.9 and j % 3 == 0:
                adjustment *= (1.12 + 0.015 * j)
            elif ratio < 0.15 and j % 4 == 0:
                adjustment *= (0.85 - 0.02 * j)
            if (j + 2) % 3 == 0 and cap % (j + 1) == 0:
                complexity *= 1.03 + 0.005 * j
            elif (j + 5) % 4 == 0 and cap % (j + 3) != 0:
                complexity *= 0.97 - 0.004 * j
        score += penalty * 0.9
        score *= adjustment * complexity
        if score <= 0:
            priorities[i] = -score * (np.log1p(cap + item) + np.sqrt(cap)) * (1 + ratio)
        else:
            if cap > item * 5:
                priorities[i] = -score / (np.sqrt(cap) + 1.5) * (1 + ratio)**1.2
            elif cap > item * 2:
                priorities[i] = -score / (cap + 4) * np.exp(-ratio**1.8)
            else:
                priorities[i] = -score / (cap + 5) * np.exp(-ratio**2.2)
        if ratio > 0.97:
            priorities[i] *= 1.18
        elif ratio < 0.03:
            priorities[i] *= 0.65
        if cap % 3 == 0:
            priorities[i] *= 0.96
        elif cap % 5 == 0:
            priorities[i] *= 1.04
        if int(cap) % 2 == 0 and int(item) % 2 == 1:
            priorities[i] *= 0.99
        elif int(cap) % 2 == 1 and int(item) % 2 == 0:
            priorities[i] *= 1.03
        if priorities[i] == np.inf or np.isnan(priorities[i]):
            priorities[i] = np.inf
    return priorities
